1400010018.css:
.card { font-family: Arial, sans-serif; font-size: 18px; text-align: left; color: #172033; background: #f5f7fb; margin: 0; padding: 0; }
*, *::before, *::after { box-sizing: border-box; }
.mcq-card { width: min(760px, 100%); max-width: 100%; margin: 0 auto; background: #fff; border: 1px solid #dbe2ee; border-radius: 8px; padding: 18px; overflow: hidden; }
.meta { color: #42506a; font-size: 14px; font-weight: 700; margin-bottom: 12px; line-height: 1.35; }
.question { white-space: pre-wrap; line-height: 1.55; font-size: 21px; margin-bottom: 16px; overflow-wrap: anywhere; }
.options { width: 100%; display: grid; gap: 10px; }
.option { width: 100%; max-width: 100%; }
.option input { position: absolute; opacity: 0; pointer-events: none; }
.choice { box-sizing: border-box; width: 100%; max-width: 100%; display: grid; grid-template-columns: 38px minmax(0, 1fr); gap: 10px; align-items: center; text-align: left; min-height: 46px; border: 1px solid #dbe2ee; border-radius: 8px; background: #fff; color: #172033; padding: 8px 12px; margin: 0; cursor: pointer; overflow: hidden; }
.choice bdi { min-width: 0; overflow-wrap: anywhere; word-break: break-word; white-space: normal; }
.choice span { display: inline-grid; place-items: center; width: 30px; height: 30px; border-radius: 999px; background: #edf3fb; font-weight: 700; }
.option input:checked + .choice { border-color: #1665d8; box-shadow: inset 0 0 0 1px #1665d8; }
.option input:checked + .choice.correct { border-color: #1f8a4c; background: #edf9f2; box-shadow: inset 0 0 0 1px #1f8a4c; }
.option input:checked + .choice.wrong { border-color: #c93535; background: #fff0f0; box-shadow: inset 0 0 0 1px #c93535; }
.feedback { display: none; margin: 7px 0 0 48px; font-size: 15px; font-weight: 700; overflow-wrap: anywhere; }
.feedback.correct { color: #1f8a4c; }
.feedback.wrong { color: #c93535; }
.option input:checked ~ .feedback { display: block; }
.hint { margin-top: 14px; color: #42506a; font-weight: 700; overflow-wrap: anywhere; }
.answer-box { width: min(760px, 100%); max-width: 100%; margin: 12px auto 0; background: #fff; border: 1px solid #dbe2ee; border-radius: 8px; padding: 16px; line-height: 1.55; overflow-wrap: anywhere; }
.explanation { white-space: pre-wrap; margin-top: 10px; }
@media (max-width: 480px) { .card { font-size: 16px; } .mcq-card, .answer-box { padding: 14px; } .question { font-size: 18px; } .choice { grid-template-columns: 34px minmax(0, 1fr); padding: 8px 10px; } .feedback { margin-left: 44px; } }
